const webhookData = $('Webhook Trigger').first().json.body || 
                    $('Webhook Trigger').first().json;

const createJobResult = $('Create Job Record').first().json;
const jobId = Array.isArray(createJobResult) 
  ? createJobResult[0]?.id 
  : createJobResult?.id;

const r2FileKey = webhookData.r2FileKey;
const r2Url = webhookData.r2Url;
const r2PublicUrl = r2Url || 
  `https://pub-70c436931e9e4611a135e7405c596611.r2.dev/${r2FileKey}`;

return [{ json: {
  r2PublicUrl,
  r2FileKey,
  jobId,
  episodeTitle: webhookData.episodeTitle,
  episodeDescription: webhookData.episodeDescription,
  chatId: webhookData.chatId || 1375806243
}}];

const result = $input.first().json;
const highlights = result.auto_highlights_result?.results || [];
const top5 = highlights
  .sort((a, b) => b.rank - a.rank)
  .slice(0, 5)
  .map(h => {
    const mins = Math.floor(h.timestamps[0].start / 60000);
    const secs = Math.floor((h.timestamps[0].start % 60000) / 1000);
    return `${String(mins).padStart(2,'0')}:${String(secs).padStart(2,'0')} — "${h.text}"`;
  });

const highlightText = top5.length > 0 
  ? top5.join('\n')
  : 'No highlights detected';

return [{ json: { 
  ...result,
  highlightTimestamps: highlightText,
  highlightCount: top5.length
}}];

const result = $input.first().json;
const highlights = $('Extract Highlight Timestamps').first().json;
let clips = [];
try {
  const text = result.content?.[0]?.text || '[]';
  const match = text.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) clips = JSON.parse(match[0]);
} catch(e) { clips = []; }
return [{ json: { ...highlights, clipSelections: clips } }];

