const text = $input.first().json.content[0].text;

// Convert markdown to basic HTML
let html = text
  // Headers
  .replace(/^### (.+)$/gm, '<h3>$1</h3>')
  .replace(/^## (.+)$/gm, '<h2>$1</h2>')
  .replace(/^# (.+)$/gm, '<h1>$1</h1>')
  // Bold
  .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  // Italic
  .replace(/\*(.+?)\*/g, '<em>$1</em>')
  // Horizontal rule
  .replace(/^---$/gm, '<hr>')
  // Unordered lists
  .replace(/^\- (.+)$/gm, '<li>$1</li>')
  .replace(/(<li>.*<\/li>\n?)+/g, '<ul>$&</ul>')
  // Line breaks to paragraphs
  .split('\n\n')
  .map(p => p.trim())
  .filter(p => p && !p.startsWith('<h') && !p.startsWith('<ul') && !p.startsWith('<hr'))
  .map(p => p.startsWith('<') ? p : `<p>${p}</p>`)
  .join('\n');

return [{ json: { ...$input.first().json, htmlContent: html } }];

const text = $('Generate LinkedIn Post').first().json.content[0].text;
const payload = JSON.stringify({
  author: 'urn:li:member:194094731',
  lifecycleState: 'PUBLISHED',
  specificContent: {
    'com.linkedin.ugc.ShareContent': {
      shareCommentary: { text: text },
      shareMediaCategory: 'NONE'
    }
  },
  visibility: {
    'com.linkedin.ugc.MemberNetworkVisibility': 'PUBLIC'
  }
});
return [{ json: { payload } }];

